body:
Future UVM on `uvm_field_queue_string(abstractions, UVM_DEFAULT) ` gives `%Error-UNSUPPORTED: t/t_0.v:29:19: Unsupported/Illegal: Assignment pattern member not underneath a supported construct: ARG`

Example test

```
`define stop $stop
`define checks(gotv,expv) do if ((gotv) != (expv)) begin $write("%%Error: %s:%0d:  got='%s' exp='%s'\n", `__FILE__,`__LINE__, (gotv), (expv)); `stop; end while(0);

typedef struct {
   string name1;
   string name2;
} names_t;

class uvm_queue;
   names_t m_queue[$];

   virtual function void push_back(names_t item);
      m_queue.push_back(item);
   endfunction
endclass

module t(/*AUTOARG*/);

   uvm_queue q;

   initial begin
      // From uvm_queue#(uvm_acs_name_struct) __local_field_names__;
      q = new;
      q.push_back('{"n1", "n2"});
      q.push_back('{"m1", "m2"});
      $display("%p", q);
      `checks(q.m_queue[0].name1, "n1");
      `checks(q.m_queue[0].name2, "n2");
      `checks(q.m_queue[1].name1, "m1");
      `checks(q.m_queue[1].name2, "m2");
      $write("*-* All Finished *-*\n");
      $finish;
   end

endmodule
```

